Those red screens are just the frontend telling you the backend never came up, so it cannot reach port 8787.

Your backend is crashing on a syntax error in server/index.ts right around the /api/batch/add route where it ends with }));. That usually means one extra or missing ) or } a few lines above, so the parser finally trips at the end of the handler. The fastest fix is to replace server/index.ts with a clean known good version and run it with a real TS runner. 

1. Replace your server/index.ts with this exact file

```ts
import express from 'express';
import cors from 'cors';
import * as extractor from './extractor.ts';
import * as queue from './queue.ts';
import * as storage from './storage.ts';

const app = express();
const PORT = 8787;

app.use(cors());
app.use(express.json({ limit: '50mb' }));

storage.initStorage().catch(console.error);

const asyncHandler =
  (fn: any) =>
  (req: any, res: any, next: any) => {
    Promise.resolve(fn(req, res, next)).catch(next);
  };

app.get('/api/health', (req, res) => {
  res.json({ ok: true });
});

app.post(
  '/api/extract',
  asyncHandler(async (req, res) => {
    const { url, templateId } = req.body || {};
    const result = await extractor.extractSingle(url, templateId);
    res.json(result);
  })
);

app.post(
  '/api/extract/test-selectors',
  asyncHandler(async (req, res) => {
    const { url, titleSelector, contentSelector } = req.body || {};
    const result = await extractor.testSelectors(url, titleSelector, contentSelector);
    res.json(result);
  })
);

app.get('/api/batch/status', (req, res) => {
  res.json(queue.getStatus());
});

app.post(
  '/api/batch/add',
  asyncHandler(async (req, res) => {
    queue.addItems(req.body.items || []);
    res.json({ success: true });
  })
);

app.post(
  '/api/batch/start',
  asyncHandler(async (req, res) => {
    await queue.startProcessing();
    res.json({ success: true });
  })
);

app.post('/api/batch/stop', (req, res) => {
  queue.stopProcessing();
  res.json({ success: true });
});

app.post('/api/batch/clear', (req, res) => {
  queue.clearQueue();
  res.json({ success: true });
});

app.get(
  '/api/batch/download',
  asyncHandler(async (req, res) => {
    const zipBuffer = await queue.createBatchZip();
    res.set('Content-Type', 'application/zip');
    res.set('Content-Disposition', 'attachment; filename=chapters.zip');
    res.send(zipBuffer);
  })
);

app.get(
  '/api/templates',
  asyncHandler(async (req, res) => {
    const data = await storage.getTemplates();
    res.json(data);
  })
);

app.post(
  '/api/templates',
  asyncHandler(async (req, res) => {
    const template = req.body;
    const templates = await storage.getTemplates();

    if (template.id === 'new' || !template.id) {
      template.id = Math.random().toString(36).substr(2, 9);
      templates.push(template);
    } else {
      const idx = templates.findIndex((t: any) => t.id === template.id);
      if (idx >= 0) templates[idx] = template;
      else templates.push(template);
    }

    await storage.saveTemplates(templates);
    res.json({ success: true });
  })
);

app.delete(
  '/api/templates/:id',
  asyncHandler(async (req, res) => {
    const { id } = req.params;
    let templates = await storage.getTemplates();
    templates = templates.filter((t: any) => t.id !== id);
    await storage.saveTemplates(templates);
    res.json({ success: true });
  })
);

app.get(
  '/api/settings',
  asyncHandler(async (req, res) => {
    const data = await storage.getSettings();
    res.json(data);
  })
);

app.post(
  '/api/settings',
  asyncHandler(async (req, res) => {
    const newSettings = req.body;
    const current = await storage.getSettings();
    const merged = { ...current, ...newSettings };
    await storage.saveSettings(merged);
    res.json({ success: true });
  })
);

app.use((err: any, req: any, res: any, next: any) => {
  console.error('Global Server Error:', err);
  if (!res.headersSent) {
    res.status(500).json({
      error: err?.message || 'Internal Server Error',
      stack: process.env.NODE_ENV === 'development' ? err?.stack : undefined,
    });
  }
});

app.listen(PORT, () => {
  console.log(`Server running at http://localhost:${PORT}`);
});
```

2. Make sure your server is not being run by plain node
   Your error stack shows node’s internal TypeScript parser running the file directly, which is fragile. Use tsx instead.

Run this once

```bash
npm i -D tsx
```

Then change your package.json scripts so server uses tsx (this is the important part). Your scripts should look like this shape. 

```json
{
  "scripts": {
    "dev": "concurrently \"npm run server\" \"vite\"",
    "server": "tsx server/index.ts"
  }
}
```

3. Start it and verify health
   Open two terminals in the project folder.

Terminal A

```bash
npm run server
```

You must see: Server running at [http://localhost:8787](http://localhost:8787)

Terminal B

```bash
npm run dev
```

Then open the app and those “Connection to backend failed” screens should disappear.

That fs.Stats deprecation warning is not what is killing the server. The syntax error is. If you do the replace above and still get a syntax error, paste your server/index.ts exactly as it exists after your edits (first 140 lines is enough) and I will pinpoint the exact character that is off.

